#pragma OPENCL EXTENSION cl_khr_fp32 : enable

#define THREADS_PER_DIM 16
#define BLOCKS_PER_DIM 16
#define THREADS_PER_BLOCK (THREADS_PER_DIM*THREADS_PER_DIM)

#define ASSUMED_NR_CLUSTERS 32

__constant float c_clusters[ASSUMED_NR_CLUSTERS*34];

__kernel void invert_mapping(__global float *input,
                             __global float *output,
                             const int npoints,
                             const int nfeatures)
{
    int point_id = get_global_id(0);
    if(point_id < npoints){
        for(int i=0; i<nfeatures; i++)
            output[point_id + npoints*i] = input[point_id*nfeatures + i];
    }
}

inline float tex1Dfetch(__global const float* arr, int idx) {
    return arr[idx];
}

__kernel void kmeansPoint(__global float *features,
                          const int nfeatures,
                          const int npoints,
                          const int nclusters,
                          __global int *membership,
                          __global float *clusters,
                          __global float *block_clusters,
                          __global int *block_deltas)
{
    const unsigned int gridDim_x = get_num_groups(0);
    const unsigned int gridDim_y = get_num_groups(1);
    const unsigned int blockIdx_x = get_group_id(0);
    const unsigned int blockIdx_y = get_group_id(1);
    const unsigned int threadIdx_x = get_local_id(0);

    const unsigned int block_id = gridDim_x*blockIdx_y + blockIdx_x;
    const unsigned int point_id = block_id * get_local_size(0) + threadIdx_x;

    int index = -1;

    if (point_id < npoints)
    {
        float min_dist = FLT_MAX;
        for (int i=0; i<nclusters; i++) {
            int cluster_base_index = i*nfeatures;
            float ans=0.0f;

            for (int j=0; j<nfeatures; j++)
            {
                int addr = point_id + j*npoints;
                float diff = tex1Dfetch(features, addr) -
                             c_clusters[cluster_base_index + j];
                ans += diff*diff;
            }
            float dist = ans;

            if (dist < min_dist) {
                min_dist = dist;
                index = i;
            }
        }
    }

    __local int deltas[THREADS_PER_BLOCK];
    if(threadIdx_x < THREADS_PER_BLOCK) {
        deltas[threadIdx_x] = 0;
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    if (point_id < npoints)
    {
        if (membership[point_id] != index) {
            deltas[threadIdx_x] = 1;
        }
        membership[point_id] = index;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    unsigned int threadids_participating = THREADS_PER_BLOCK / 2;
    while(threadids_participating > 1) {
        if(threadIdx_x < threadids_participating) {
            deltas[threadIdx_x] += deltas[threadIdx_x + threadids_participating];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
        threadids_participating /= 2;
    }
    if(threadIdx_x < 1) {
        deltas[0] += deltas[1];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    if(threadIdx_x == 0) {
        block_deltas[blockIdx_y * gridDim_x + blockIdx_x] = deltas[0];
    }

    // GPU_NEW_CENTER_REDUCTION logic
    // Assuming THREADS_PER_BLOCK >= nfeatures * nclusters
    int center_id = threadIdx_x / nfeatures;
    int dim_id = threadIdx_x % nfeatures;

    __local int new_center_ids[THREADS_PER_BLOCK];
    new_center_ids[threadIdx_x] = index;
    barrier(CLK_LOCAL_MEM_FENCE);

    int base_point_id = point_id - threadIdx_x;
    float accumulator = 0.0f;

    if(threadIdx_x < nfeatures * nclusters)
    {
        for(int i = 0; i < THREADS_PER_BLOCK; i++) {
            float val = tex1Dfetch(features, base_point_id * nfeatures + dim_id + i * nfeatures);
            if(new_center_ids[i] == center_id)
                accumulator += val;
        }

        int block_idx = blockIdx_y * gridDim_x + blockIdx_x;
        block_clusters[block_idx * nclusters * nfeatures + threadIdx_x] = accumulator;
    }
}
